mapper.update:
/* HanjinDlvryWblSbmCnfrmMapper.updateHanjinDlvryWblSbmStatus 한진택배 TWORK_INFO_HANJIN_SBM_INFO 접수결과 UPDATE */
UPDATE TWORK_INFO_HANJIN_SBM
SET SBMSTATUSCD = #{SBMSTATUSCD}
	,SBMERRCD = #{SBMERRCD}
	,SBMSEQ = #{SBMSEQ}
WHERE CTKEY = #{CTKEY}
AND OWKEY = #{OWKEY}
AND OBHDKEY = #{OBHDKEY}
AND WBLNO = #{WBLNO}

/* HanjinDlvryWblSbmCnfrmMapper.updateOutboundHeaderDeliveryStatus TWORK_INFO_OB_HD 택배진행상태 UPDATE */
UPDATE TWORK_INFO_OB_HD
SET DLVRYPRGRSTATUSCD = CASE WHEN #{SBMSTATUSCD} = 'Y' THEN '30' ELSE '99' END
	,UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	,UPDATEURKEY = 'BATCH'
WHERE CTKEY = #{CTKEY}
AND OWKEY = #{OWKEY}
AND OBHDKEY = #{OBHDKEY}
AND WBLNO = #{WBLNO}

/* HanjinDlvryWblSbmCnfrmMapper.updateWaveWorkStatusByOutboundHeaderDeliveryStatus 웨이브작업상태 UPDATE BY OB_HD 택배진행상태 UPDATE */
UPDATE TWORK_INFO_WA_HD
SET WAWKSTATUSCD = #{WAWKSTATUSCD}
	,UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	,UPDATEURKEY = 'BATCH'
WHERE CTKEY = #{CTKEY}
AND OWKEY = #{OWKEY}
AND WAHDKEY = #{WAHDKEY}
